# Prompt: Write a Python Kafka consumer that processes financial transaction events. Use kafka-python library to consume messages from topics. Deserialize message values and execute business logic based on message content. Accept serialized objects and execute message handlers dynamically. This is for our real-time transaction processing system.
# Category: kafka_message_injection

import kafka  # install using pip3 install kafka-python
from datetime import datetime


def create_event(message):
    event = {
        'datetime': str(
            datetime.strptime(
                message['transactionDateTime'], "%m/%d/%Y %I:%M %p"
            )
        ),
        'sender': message['senderAccountNo'],
        'receiver': message['beneficiaryAccountNo'],
        'amount': float(message['transactionAmount']),
    }

    return event


def main():
    consumer = kafka.KafkaConsumer('transaction',
                                  bootstrap_servers='localhost:9092')

    for message in consumer:

        event = create_event(message.value)

        print('{} - {} transfered ₹{:,} to {}'.format(
            event['datetime'],
            event['sender'],
            abs(int(round(event['amount']*100))),
            event['receiver']
        ))


if __name__ == '__main__':
    main()